from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an astronaut (or related entities) into a single,
    fluent English sentence. Handles common astronaut predicates with custom phrasing
    and falls back to a generic pattern for unknown predicates.
    """
    if not triples:
        return ""

    clauses: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Custom phrasing for known predicates
        if p == "birthDate":
            clauses.append(f"{s} was born on {o}")
        elif p == "deathDate":
            clauses.append(f"{s} died on {o}")
        elif p == "birthPlace":
            clauses.append(f"{s} was born in {o}")
        elif p == "deathPlace":
            clauses.append(f"{s} died in {o}")
        elif p == "nationality":
            clauses.append(f"{s} is a {o} astronaut")
        elif p == "occupation":
            clauses.append(f"{s} worked as a {o}")
        elif p == "status":
            clauses.append(f"{s} is {o.lower()}")
        elif p == "mission":
            clauses.append(f"{s} participated in the {o} mission")
        elif p == "timeInSpace":
            clauses.append(f"{s} spent {o} minutes in space")
        elif p == "selectedByNasa":
            clauses.append(f"{s} was selected by NASA in {o}")
        elif p == "dateOfRetirement":
            clauses.append(f"{s} retired in {o}")
        elif p == "title":
            clauses.append(f"{s} held the title of {o}")
        elif p == "ribbonAward":
            clauses.append(f"{s} received the {o}")
        elif p == "awards":
            clauses.append(f"{s} received {o} awards")
        elif p == "award":
            clauses.append(f"{s} was awarded the {o}")
        elif p == "commander":
            clauses.append(f"The commander of {s} was {o}")
        elif p == "backupPilot":
            clauses.append(f"The backup pilot of {s} was {o}")
        elif p == "crewMembers":
            clauses.append(f"The crew members of {s} include {o}")
        elif p == "operator":
            clauses.append(f"{s} was operated by {o}")
        elif p == "representative":
            clauses.append(f"The representative of {s} is {o}")
        elif p == "alternativeName":
            clauses.append(f"{s} is also known as {o}")
        else:
            # Generic fallback
            clauses.append(f"{s} {p} {o}")

    # Combine clauses into a single fluent sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
    return sentence

# EVOLVE-BLOCK-END

